"use client";

import React, { useState, useRef, useEffect, useCallback } from "react";
import {
  Box,
  Container,
  Typography,
  TextField,
  Avatar,
  Chip,
  useTheme,
  alpha,
  Paper,
  Grid,
  Button,
  AppBar,
  Toolbar,
  Popper,
  ClickAwayListener,
  MenuList,
  MenuItem,
  ListItemIcon,
  ListItemText,
  Fade,
  Accordion,
  AccordionSummary,
  AccordionDetails,
  Divider,
} from "@mui/material";
import {
  Send as SendIcon,
  Security as SecurityIcon,
  Assignment as AssignmentIcon,
  CheckCircle as CheckCircleIcon,
  Error as ErrorIcon,
  ExpandMore as ExpandMoreIcon,
  Code as CodeIcon,
  SmartToy as SmartToyIcon,
  PlayArrow as PlayArrowIcon,
  CallMade as CallMadeIcon,
  CallReceived as CallReceivedIcon,
} from "@mui/icons-material";
import { useRouter } from "next/navigation";
import { useProtectedRoute } from "@/hooks/useProtectedRoute";
import { CircularProgress } from "@mui/material";
import { fetchEventSource } from "@microsoft/fetch-event-source";
import moment from "moment";
import ComplianceReportCards from "../components/ComplianceReportCards";
import ApprovalsCards from "../components/ApprovalsCards";
import TowerCards from "../components/TowerCards";

// ... (keep all existing interfaces)

export default function DashboardPage() {
  // ... (keep all existing state and functions)

  // Add state for prompt message
  const [promptMessage, setPromptMessage] = useState<{agent: Agent; message: string} | null>(null);

  // Update handleSendMessage to set prompt message
  const handleSendMessage = async () => {
    if (!inputValue.trim()) return;

    const lowerInput = inputValue.toLowerCase();

    let mentionedAgent = agents.find((agent) =>
      lowerInput.includes(`@${agent.name.toLowerCase()}`),
    );

    if (!mentionedAgent) {
      mentionedAgent = agents[0];
    }

    // Set prompt message
    setPromptMessage({
      agent: mentionedAgent,
      message: inputValue,
    });

    setIsTyping(true);

    try {
      // Step 1: Get or create conversation
      const convId = await getOrCreateConversation(mentionedAgent.name);

      // Step 2: Start chat and get runId
      const runId = await startChat(
        convId,
        inputValue.replace(`@${mentionedAgent.name}`, "").trim(),
        mentionedAgent.agentId,
        mentionedAgent.id,
      );

      // Create new card
      const newCardId = Date.now().toString();
      const newCard: AgentCard = {
        id: newCardId,
        agent: mentionedAgent.id as "compliance" | "approvals" | "tower",
        title:
          mentionedAgent.id === "compliance"
            ? "Compliance Report"
            : mentionedAgent.id === "approvals"
              ? "Approvals Required"
              : "Tower Overview",
        timestamp: new Date(),
        runId: runId,
        streaming: true,
        convId: convId,
      };

      setActiveCards((prev) => [...prev, newCard]);
      setStreamingCard(mentionedAgent.id);

      // Step 3: Connect to SSE stream
      await handleStreamData(runId, newCardId, lowerInput, convId);
    } catch (error) {
      console.error("Error in conversation flow:", error);
      const errorCard: AgentCard = {
        id: Date.now().toString(),
        agent: "compliance",
        title: "Error",
        timestamp: new Date(),
        streamData: {
          steps: [
            {
              title: "Error",
              description:
                error instanceof Error
                  ? error.message
                  : "Failed to start conversation",
              timestamp: moment().format("hh:mm:ss"),
            },
          ],
        },
      };
      setActiveCards((prev) => [...prev, errorCard]);
    } finally {
      setIsTyping(false);
    }

    setInputValue("");
  };

  // Update the renderStreamSteps function to return a single accordion
  const renderStreamSteps = (card: AgentCard) => {
    if (
      !card.streamData?.steps &&
      !card.agentStreamData?.thoughtsAndtoolsAction
    ) {
      return null;
    }

    const steps = card.streamData?.steps || [];
    const [expanded, setExpanded] = useState(true);

    if (steps.length === 0) return null;

    return (
      <Accordion
        expanded={expanded}
        onChange={() => setExpanded(!expanded)}
        sx={{
          mt: 2,
          mb: 2,
          bgcolor: alpha(theme.palette.primary.main, 0.02),
          border: `1px solid ${alpha(theme.palette.primary.main, 0.1)}`,
          borderRadius: 2,
          '&:before': { display: 'none' },
        }}
      >
        <AccordionSummary
          expandIcon={<ExpandMoreIcon />}
          sx={{
            minHeight: 56,
            '& .MuiAccordionSummary-content': {
              alignItems: 'center',
              gap: 1,
            },
          }}
        >
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
            <CodeIcon sx={{ color: theme.palette.primary.main }} />
            <Typography variant="subtitle2" sx={{ fontWeight: 600 }}>
              Agent Execution Steps ({steps.length})
            </Typography>
          </Box>
        </AccordionSummary>
        <AccordionDetails>
          {steps.map((step, index) => (
            <Box key={index}>
              {index > 0 && <Divider sx={{ my: 1.5 }} />}
              <Box sx={{ display: 'flex', flexDirection: 'column', gap: 1 }}>
                <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                  {step.title.includes("Calling") && (
                    <CallMadeIcon sx={{ fontSize: 18, color: theme.palette.warning.main }} />
                  )}
                  {step.title.includes("Response") && (
                    <CallReceivedIcon sx={{ fontSize: 18, color: theme.palette.success.main }} />
                  )}
                  {step.title.includes("Thought") && (
                    <SmartToyIcon sx={{ fontSize: 18, color: theme.palette.info.main }} />
                  )}
                  {step.title.includes("Executing") && (
                    <PlayArrowIcon sx={{ fontSize: 18, color: theme.palette.primary.main }} />
                  )}
                  {step.title.includes("Error") && (
                    <ErrorIcon sx={{ fontSize: 18, color: theme.palette.error.main }} />
                  )}
                  <Typography variant="body2" sx={{ fontWeight: 500, flex: 1 }}>
                    {step.title}
                  </Typography>
                  {step.timestamp && (
                    <Typography variant="caption" color="text.secondary">
                      {step.timestamp}
                    </Typography>
                  )}
                </Box>
                
                <Typography variant="body2" color="text.secondary" sx={{ ml: 3.5 }}>
                  {step.description}
                </Typography>

                {step.toolArgs && (
                  <Paper
                    variant="outlined"
                    sx={{
                      ml: 3.5,
                      p: 1.5,
                      bgcolor: alpha(theme.palette.background.default, 0.5),
                      fontFamily: "monospace",
                      fontSize: "0.875rem",
                      overflow: "auto",
                    }}
                  >
                    <pre style={{ margin: 0 }}>
                      {JSON.stringify(step.toolArgs, null, 2)}
                    </pre>
                  </Paper>
                )}

                {step.toolResponse && (
                  <Paper
                    variant="outlined"
                    sx={{
                      ml: 3.5,
                      p: 1.5,
                      mt: 1,
                      bgcolor: alpha(theme.palette.success.main, 0.05),
                      fontFamily: "monospace",
                      fontSize: "0.875rem",
                      overflow: "auto",
                    }}
                  >
                    <Typography
                      variant="caption"
                      color="success.main"
                      sx={{ display: "block", mb: 1 }}
                    >
                      Response:
                    </Typography>
                    <pre style={{ margin: 0 }}>
                      {typeof step.toolResponse === "string"
                        ? step.toolResponse
                        : JSON.stringify(step.toolResponse, null, 2)}
                    </pre>
                  </Paper>
                )}
              </Box>
            </Box>
          ))}
        </AccordionDetails>
      </Accordion>
    );
  };

  // Update the return statement with improved UI
  return (
    <Box
      sx={{
        height: "100vh",
        display: "flex",
        flexDirection: "column",
        bgcolor: theme.palette.background.default,
        overflow: "hidden",
      }}
    >
      <Box
        sx={{
          flex: 1,
          overflow: "auto",
          px: 2,
          py: 2,
        }}
      >
        <Container maxWidth="xl">
          {activeCards.length > 0 && (
            <Box sx={{ mb: 4 }}>
              <Grid container spacing={3}>
                {activeCards.map((card) => {
                  // Find the prompt for this card (in a real app, you'd store this with the card)
                  const cardPrompt = promptMessage;
                  
                  return (
                    <Grid item xs={12} key={card.id}>
                      <Paper sx={{ 
                        p: 3,
                        borderRadius: 2,
                        bgcolor: 'background.paper',
                      }}>
                        {/* Prompt Message Section */}
                        {cardPrompt && (
                          <Box sx={{ mb: 3, pb: 2, borderBottom: `1px solid ${theme.palette.divider}` }}>
                            <Typography variant="caption" color="text.secondary" gutterBottom sx={{ display: 'block', mb: 1 }}>
                              Your request:
                            </Typography>
                            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1.5 }}>
                              <Avatar sx={{ bgcolor: getAgentColor(card.agent), width: 28, height: 28 }}>
                                {card.agent === 'compliance' && <AssignmentIcon sx={{ fontSize: 16 }} />}
                                {card.agent === 'approvals' && <CheckCircleIcon sx={{ fontSize: 16 }} />}
                                {card.agent === 'tower' && <SecurityIcon sx={{ fontSize: 16 }} />}
                              </Avatar>
                              <Typography variant="body1" sx={{ fontWeight: 500 }}>
                                {cardPrompt.message}
                              </Typography>
                              <Typography variant="caption" color="text.secondary" sx={{ ml: 'auto' }}>
                                {card.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                              </Typography>
                            </Box>
                          </Box>
                        )}

                        {/* Streaming Steps Accordion */}
                        {renderStreamSteps(card)}

                        {/* Streaming Indicator */}
                        {card.streaming && streamingCard === card.agent && (
                          <Paper
                            sx={{
                              p: 2,
                              mt: 2,
                              bgcolor: alpha(getAgentColor(card.agent), 0.05),
                              border: `1px solid ${alpha(getAgentColor(card.agent), 0.3)}`,
                              borderRadius: 2,
                              animation: "pulse 1.5s infinite",
                              "@keyframes pulse": {
                                "0%": { opacity: 0.6 },
                                "50%": { opacity: 1 },
                                "100%": { opacity: 0.6 },
                              },
                            }}
                          >
                            <Box sx={{ display: "flex", alignItems: "center", gap: 2 }}>
                              <Avatar
                                sx={{
                                  bgcolor: getAgentColor(card.agent),
                                  width: 32,
                                  height: 32,
                                }}
                              >
                                {card.agent === "compliance" && <AssignmentIcon sx={{ fontSize: 20 }} />}
                                {card.agent === "approvals" && <CheckCircleIcon sx={{ fontSize: 20 }} />}
                                {card.agent === "tower" && <SecurityIcon sx={{ fontSize: 20 }} />}
                              </Avatar>
                              <Box>
                                <Typography variant="subtitle2" sx={{ color: getAgentColor(card.agent) }}>
                                  {card.agent === "compliance"
                                    ? "Compliance Agent"
                                    : card.agent === "approvals"
                                      ? "Approvals Agent"
                                      : "Tower Agent"}{" "}
                                  is responding...
                                </Typography>
                                <Typography variant="caption" color="text.secondary">
                                  Generating response ⚡
                                </Typography>
                              </Box>
                            </Box>
                          </Paper>
                        )}

                        {/* Card Content */}
                        {card.content && !card.streaming && (
                          <Box sx={{ mt: 3 }}>
                            <Typography variant="subtitle2" color="text.secondary" gutterBottom>
                              Response:
                            </Typography>
                            {card.content}
                          </Box>
                        )}
                      </Paper>
                    </Grid>
                  );
                })}
              </Grid>
            </Box>
          )}

          {isTyping && !streamingCard && (
            <Paper
              sx={{
                p: 2,
                mb: 2,
                bgcolor: alpha(theme.palette.primary.main, 0.05),
                maxWidth: 200,
              }}
            >
              <Typography variant="body2" color="text.secondary">
                AI Assistant is thinking...
              </Typography>
            </Paper>
          )}

          <div ref={messagesEndRef} />
        </Container>
      </Box>

      {/* Chat Input Section - Keep as is */}
      <Paper
        elevation={3}
        sx={{
          p: 2,
          borderTop: `1px solid ${theme.palette.divider}`,
          bgcolor: "background.paper",
          position: "sticky",
          bottom: 0,
          zIndex: 1100,
        }}
        ref={menuAnchorRef}
      >
        {/* ... keep existing chat input code ... */}
        <Container maxWidth="xl">
          <Box sx={{ display: "flex", flexDirection: "column", gap: 1.5 }}>
            <Box
              sx={{
                display: "flex",
                gap: 1,
                flexWrap: "wrap",
                alignItems: "center",
              }}
            >
              {agents.map((agent) => (
                <Chip
                  key={agent.id}
                  icon={agent.icon}
                  label={`@${agent.name}`}
                  onClick={() => handleAgentClick(agent.name)}
                  sx={{
                    bgcolor: activeConversations.has(agent.name)
                      ? alpha(agent.color, 0.2)
                      : alpha(agent.color, 0.1),
                    color: agent.color,
                    borderColor: agent.color,
                    "&:hover": {
                      bgcolor: alpha(agent.color, 0.3),
                    },
                  }}
                  variant="outlined"
                  size="small"
                />
              ))}
            </Box>

            <Box sx={{ position: "relative" }}>
              <Box sx={{ display: "flex", gap: 1 }}>
                <TextField
                  fullWidth
                  placeholder="Type @ to mention an agent or click chips above..."
                  value={inputValue}
                  onChange={handleInputChange}
                  onKeyPress={handleKeyPress}
                  variant="outlined"
                  size="small"
                  inputRef={inputRef}
                  sx={{
                    "& .MuiOutlinedInput-root": {
                      borderRadius: 2,
                      bgcolor: alpha(theme.palette.background.default, 0.5),
                    },
                  }}
                />
                <Button
                  variant="contained"
                  onClick={handleSendMessage}
                  disabled={!inputValue.trim()}
                  sx={{
                    bgcolor: theme.palette.primary.main,
                    color: "white",
                    px: 4,
                    "&:hover": {
                      bgcolor: theme.palette.primary.dark,
                    },
                    "&.Mui-disabled": {
                      bgcolor: alpha(theme.palette.primary.main, 0.3),
                    },
                  }}
                >
                  Send
                </Button>
              </Box>

              {showAgentMenu && filteredAgents.length > 0 && (
                <Popper
                  open={showAgentMenu}
                  anchorEl={menuAnchorRef.current}
                  placement="top-start"
                  transition
                  sx={{ zIndex: 1300, width: 300 }}
                >
                  {({ TransitionProps }) => (
                    <Fade {...TransitionProps} timeout={350}>
                      <Paper elevation={4}>
                        <ClickAwayListener
                          onClickAway={() => setShowAgentMenu(false)}
                        >
                          <MenuList>
                            {filteredAgents.map((agent) => (
                              <MenuItem
                                key={agent.id}
                                onClick={() => handleAgentSelect(agent)}
                                sx={{
                                  "&:hover": {
                                    bgcolor: alpha(agent.color, 0.1),
                                  },
                                }}
                              >
                                <ListItemIcon
                                  sx={{ color: agent.color, minWidth: 36 }}
                                >
                                  {agent.icon}
                                </ListItemIcon>
                                <ListItemText
                                  primary={`@${agent.name}`}
                                  secondary={agent.description}
                                  primaryTypographyProps={{
                                    sx: { fontWeight: 500, color: agent.color },
                                  }}
                                  secondaryTypographyProps={{
                                    sx: { fontSize: "0.75rem" },
                                  }}
                                />
                                {activeConversations.has(agent.name) && (
                                  <Chip
                                    size="small"
                                    label="Active"
                                    color="success"
                                    variant="outlined"
                                    sx={{ ml: 1, height: 20 }}
                                  />
                                )}
                              </MenuItem>
                            ))}
                          </MenuList>
                        </ClickAwayListener>
                      </Paper>
                    </Fade>
                  )}
                </Popper>
              )}
            </Box>
          </Box>
        </Container>
      </Paper>
    </Box>
  );
}